const input = $input.first().json;

const recordId =
  input.query?.id ||
  input.query?.recordId ||
  input.body?.id ||
  input.body?.recordId ||
  input.id ||
  input.recordId;

if (!recordId) {
  return [{ json: { ok: false, error: 'missing_recordId', receivedQuery: input.query || null } }];
}

return [{ json: { recordId: String(recordId).trim(), id: String(recordId).trim() } }];

const proxy = $('Proxy Logic').first().json;
const requestedId = String(proxy.recordId || proxy.id || '').trim();

const inputItems = $input.all();
let records = [];
for (const item of inputItems) {
  const value = item.json;
  if (Array.isArray(value.data)) records.push(...value.data);
  else if (Array.isArray(value.records)) records.push(...value.records);
  else if (value.data && typeof value.data === 'object') records.push(value.data);
  else records.push(value);
}

function asText(value) {
  if (value === undefined || value === null) return '';
  if (Array.isArray(value)) return value.map(asText).filter(Boolean).join(', ');
  if (typeof value === 'object') return value.value || value.name || value.label || value.text || value.title || JSON.stringify(value);
  return String(value).trim();
}

const record =
  records.find((entry) => {
    const fields = entry.fields || entry;
    const possibleIds = [entry.id, entry.recordId, entry._id, fields.id, fields.recordId, fields['Record ID'], fields['ID']];
    return possibleIds.some((v) => asText(v) === requestedId);
  }) || (records.length === 1 ? records[0] : null);

if (!requestedId) {
  return [{ json: { ok: false, error: 'recordId mancante' } }];
}
if (!record) {
  return [{ json: { ok: false, error: `Record non trovato: ${requestedId}`, recordsFound: records.length } }];
}

const fields = record.fields || record;
function pick(...names) {
  for (const n of names) {
    const v = fields[n];
    if (v !== undefined && v !== null && asText(v) !== '') return asText(v);
  }
  return '';
}

const response = {
  ok: true,
  id: requestedId,
  recordId: requestedId,
  nome: pick('Nome', 'nome'),
  cognome: pick('Cognome', 'cognome'),
  ruolo: pick('Ruolo', 'ruolo'),
  azienda: pick('IA', 'Strumento IA', 'Azienda', 'azienda')
};

if (!response.nome && !response.cognome && !response.ruolo && !response.azienda) {
  response.ok = false;
  response.error = 'Record trovato, ma campi anagrafici vuoti. Controlla i nomi dei campi Softr.';
  response.availableFields = Object.keys(fields).join(' | ');
}

return [{ json: response }];
